def assess(record: dict) -> str:
    required_fields = {"case_id", "extra_policy", "json_schema", "valid_fixture", "business_rule"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = record["extra_policy"] == "forbid"
    return "PASS" if ok else "REJECT_SCHEMA"

valid = {"case_id": "CASO-CUS-042-1A", **{"extra_policy": "forbid", "json_schema": True, "valid_fixture": True, "business_rule": True}}
invalid = {"case_id": "CASO-CUS-042-1A", **{"extra_policy": "", "json_schema": True, "valid_fixture": True, "business_rule": True}}
incomplete = dict(valid)
if "business_rule" in incomplete:
    del incomplete["business_rule"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

